package cn.nobeta.dingdong.order.service;
import cn.nobeta.dingdong.common.rpc.ProductInventoryFacade;import cn.nobeta.dingdong.order.domain.MallOrder;import cn.nobeta.dingdong.order.mapper.OrderMapper;import org.junit.jupiter.api.Test;import org.springframework.test.util.ReflectionTestUtils;import static org.mockito.ArgumentMatchers.*;import static org.mockito.Mockito.*;
class OrderTimeoutTest {@Test void closesOnlyPendingOrderAndReleasesStock(){OrderMapper mapper=mock(OrderMapper.class);CartService cart=mock(CartService.class);OrderOutboxService outbox=mock(OrderOutboxService.class);ProductInventoryFacade product=mock(ProductInventoryFacade.class);MallOrder order=new MallOrder();order.setId(8L);order.setOrderNo("DD1");order.setStatus("PENDING_PAYMENT");when(mapper.findByOrderNo("DD1")).thenReturn(order);when(mapper.updateStatus("DD1","PENDING_PAYMENT","CANCELED")).thenReturn(1);OrderService service=new OrderService(mapper,cart,outbox);ReflectionTestUtils.setField(service,"productFacade",product);service.closeUnpaidOrder("DD1");verify(product).unlockInventory("DD1");verify(mapper).insertStatusLog(eq(8L),eq("PENDING_PAYMENT"),eq("CANCELED"),eq("SYSTEM"),isNull(),contains("超时"));}}
